fn solve(n: i64) -> bool {
    let s = n.to_string();
    let digits: Vec<u8> = s.chars().map(|c| c.to_digit(10).unwrap()).collect();
    let sum: u64 = digits.iter().sum();
    let product: u64 = digits.iter().try_fold(1, |acc, &d| {
        acc * d as u64
    });
    let total = sum + product;
    let n_u64 = n as u64;
    n_u64 % total == 0
}
